/** Flat list of all icon entries */
export function getAllIcons(): IconEntry[] {
  return ICON_CATALOG.flatMap((c) => c.icons);
}

/** Total icon count */
export function getIconCount(): number {
  return ICON_CATALOG.reduce((n, c) => n + c.icons.length, 0);
}

/** Category count */
export function getCategoryCount(): number {
  return ICON_CATALOG.length;
}
